import{_ as e,o as t,c as i,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"事实表、维度表与星型模型","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"dimensional-modeling"},"headers":[],"relativePath":"05-backend-data/notes/cache-messaging-storage/21-dimensional-modeling.md","filePath":"05-backend-data/notes/cache-messaging-storage/21-dimensional-modeling.md","lastUpdated":1784382745000}'),r={name:"05-backend-data/notes/cache-messaging-storage/21-dimensional-modeling.md"};function o(l,a,d,s,h,c){return t(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="事实表、维度表与星型模型" tabindex="-1">事实表、维度表与星型模型 <a class="header-anchor" href="#事实表、维度表与星型模型" aria-label="Permalink to &quot;事实表、维度表与星型模型&quot;">​</a></h1><p>维度建模把可度量业务过程放事实表，把描述性上下文放维度表。第一步是声明事实表粒度；粒度不清会造成重复计数，任何主键和BI工具都无法自动修复。</p><h2 id="_1-数据流与决策边界" tabindex="-1">1. 数据流与决策边界 <a class="header-anchor" href="#_1-数据流与决策边界" aria-label="Permalink to &quot;1. 数据流与决策边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;源事实/事件&quot;] --&gt; B[&quot;传输与处理&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;模型/存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;查询与指标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;质量、对账与重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>维度模型首先固定 grain：事实表每一行代表什么业务事件，决定可加指标、唯一键和允许连接的维度版本。事实必须在该粒度上可对账；SCD2 的有效时间区间与 surrogate key 用来保留历史语义，而不是给表增加形式上的字段。</p><h2 id="_2-grain" tabindex="-1">2. Grain <a class="header-anchor" href="#_2-grain" aria-label="Permalink to &quot;2. Grain&quot;">​</a></h2><p>机制：事实表一行准确代表什么。</p><p>实际用途：每订单行/每支付尝试/每日快照。</p><p>失败方式：混合订单与订单项粒度。</p><p>验证：用自然业务键和示例声明。</p><p>取舍：细粒度灵活但数据量大。</p><p>Grain 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_3-fact" tabindex="-1">3. Fact <a class="header-anchor" href="#_3-fact" aria-label="Permalink to &quot;3. Fact&quot;">​</a></h2><p>机制：可加、半可加或不可加度量及维度外键。</p><p>实际用途：amount_cents、quantity、duration。</p><p>失败方式：存百分比后直接求和。</p><p>验证：按度量聚合规则测试。</p><p>取舍：原子事实可重算但查询更重。</p><p>Fact 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_4-dimension" tabindex="-1">4. Dimension <a class="header-anchor" href="#_4-dimension" aria-label="Permalink to &quot;4. Dimension&quot;">​</a></h2><p>机制：描述谁/什么/何时/哪里/为什么。</p><p>实际用途：用户、商品、渠道、日期。</p><p>失败方式：把频繁变化高基数事件塞维度。</p><p>验证：唯一业务键和属性历史测试。</p><p>取舍：宽维度易用但变化治理。</p><p>Dimension 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_5-star-schema" tabindex="-1">5. Star schema <a class="header-anchor" href="#_5-star-schema" aria-label="Permalink to &quot;5. Star schema&quot;">​</a></h2><p>机制：事实表直接连接反规范化维度。</p><p>实际用途：BI查询简单、join少。</p><p>失败方式：把规范化OLTP表原样当星型。</p><p>验证：执行计划与用户语义验证。</p><p>取舍：重复属性换查询便利。</p><p>Star schema 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_6-surrogate-key" tabindex="-1">6. Surrogate key <a class="header-anchor" href="#_6-surrogate-key" aria-label="Permalink to &quot;6. Surrogate key&quot;">​</a></h2><p>机制：仓库生成维度版本键。</p><p>实际用途：支持SCD和多源业务键。</p><p>失败方式：只用可复用业务ID。</p><p>验证：映射唯一/unknown行测试。</p><p>取舍：增加ETL映射步骤。</p><p>Surrogate key 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_7-scd-type-1" tabindex="-1">7. SCD Type 1 <a class="header-anchor" href="#_7-scd-type-1" aria-label="Permalink to &quot;7. SCD Type 1&quot;">​</a></h2><p>机制：覆盖属性历史。</p><p>实际用途：修正拼写/不需历史。</p><p>失败方式：用于地区历史导致过去报表改变。</p><p>验证：变更前后历史查询测试。</p><p>取舍：简单但丢历史。</p><p>SCD Type 1 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_8-scd-type-2" tabindex="-1">8. SCD Type 2 <a class="header-anchor" href="#_8-scd-type-2" aria-label="Permalink to &quot;8. SCD Type 2&quot;">​</a></h2><p>机制：新维度行保存有效期/当前标志。</p><p>实际用途：保留客户地区、计划版本。</p><p>失败方式：有效区间重叠/空洞。</p><p>验证：排除约束/质量测试。</p><p>取舍：历史准确但join与存储增加。</p><p>SCD Type 2 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_9-date-dimension" tabindex="-1">9. Date dimension <a class="header-anchor" href="#_9-date-dimension" aria-label="Permalink to &quot;9. Date dimension&quot;">​</a></h2><p>机制：日期属性、财年、节假日等。</p><p>实际用途：按业务日历分析。</p><p>失败方式：只从timestamp临时提取导致定义不一。</p><p>验证：日历范围/时区/财年测试。</p><p>取舍：集中语义但需维护。</p><p>Date dimension 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_10-degenerate-dimension" tabindex="-1">10. Degenerate dimension <a class="header-anchor" href="#_10-degenerate-dimension" aria-label="Permalink to &quot;10. Degenerate dimension&quot;">​</a></h2><p>机制：业务单号留在事实表而无独立维表。</p><p>实际用途：订单号筛选/下钻。</p><p>失败方式：把大量描述字段都称退化维度。</p><p>验证：查询使用和唯一性验证。</p><p>取舍：减少join但不承载属性。</p><p>Degenerate dimension 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_11-snapshot-fact" tabindex="-1">11. Snapshot fact <a class="header-anchor" href="#_11-snapshot-fact" aria-label="Permalink to &quot;11. Snapshot fact&quot;">​</a></h2><p>机制：周期快照或累积快照描述状态。</p><p>实际用途：库存日结、订单里程碑。</p><p>失败方式：与交易事实混合后重复求和。</p><p>验证：按snapshot_date和grain测试。</p><p>取舍：趋势方便但会重复存储。</p><p>Snapshot fact 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要能力</th><th>边界</th></tr></thead><tbody><tr><td>Transaction fact</td><td>每业务事件</td><td>量大最灵活</td></tr><tr><td>Periodic snapshot</td><td>每周期状态</td><td>不可跨日简单求和</td></tr><tr><td>Accumulating snapshot</td><td>流程一行多里程碑</td><td>更新与迟到复杂</td></tr><tr><td>SCD1</td><td>覆盖</td><td>无历史</td></tr><tr><td>SCD2</td><td>版本区间</td><td>join复杂</td></tr></tbody></table><h2 id="_13-完整案例-订单收入星型模型" tabindex="-1">13. 完整案例：订单收入星型模型 <a class="header-anchor" href="#_13-完整案例-订单收入星型模型" aria-label="Permalink to &quot;13. 完整案例：订单收入星型模型&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>订单含多商品、退款和多币种；需要按商品/地区/日收入，金额精确。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>grain定义每订单项每次财务事件，而非每订单。</li><li>fact保存原币/本位币整数金额、quantity、event_type。</li><li>连接date、product、customer_region、currency_rate_version维度。</li><li>退款用独立负向事实/明确类型，不覆盖原销售。</li><li>用ledger总额按日/tenant对账。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>聚合不会因订单多项或维度join重复，退款可追踪。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>sum事实与财务ledger守恒；每事实业务键唯一；未知维度落unknown。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>把订单总额复制到每item会按商品求和倍增；必须按grain分配/保存item金额。</p><h3 id="恢复与重跑" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>以“订单项 + 财务事件 ID”作为稳定事实键重建受影响日期，重复销售或退款事件用该键拒绝。修正先写 shadow fact 分区，分别对账原币、本位币、数量和退款净额；确认每个事实只连接一个维度版本后再交换分区，旧版本保留用于报表回滚。</p><h2 id="_14-完整案例-客户地区scd2" tabindex="-1">14. 完整案例：客户地区SCD2 <a class="header-anchor" href="#_14-完整案例-客户地区scd2" aria-label="Permalink to &quot;14. 完整案例：客户地区SCD2&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>客户7月从上海迁北京，历史订单应保留当时地区，新订单用北京。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>维度行含customer_sk、business_id、valid_from/to、is_current。</li><li>变更关闭上海版本并插北京版本，同一业务时间轴不重叠。</li><li>事实按订单发生时刻查有效维度sk。</li><li>迟到订单重新按event time映射，不用当前行。</li><li>质量检查区间和一个current。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>六月收入属于上海，八月属于北京。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>边界时刻、迟到、重复变更、相同时间更新。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>事实只存customer_id并运行时join current维度会改写历史；保存版本surrogate key。</p><h3 id="恢复与重跑-1" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑-1" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>客户变更以 business ID、source version 和 valid_from 幂等应用。迟到变更先在隔离维度中重新切分受影响时间区间，再重映射该区间事实；检查无重叠、无意外空档且恰有一个 current 后原子替换客户时间轴，不能直接修改现有区间造成历史事实暂时多重匹配。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期信号与恢复</th><th>禁止结果</th></tr></thead><tbody><tr><td>重复输入</td><td><code>fact_row_count</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>乱序和迟到</td><td><code>grain_duplicates</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>源schema变化</td><td><code>unknown_dimension_rate</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>任务中途崩溃</td><td><code>scd_overlap</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>下游429/503</td><td><code>scd_gap</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>checkpoint损坏</td><td><code>ledger_reconciliation</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>质量规则失败</td><td><code>late_fact_rate</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>回填与实时并发</td><td><code>dimension_change</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>权限撤销</td><td><code>query_scan</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>成本超预算</td><td><code>semantic_test_fail</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr></tbody></table><h2 id="_16-数据质量与对账" tabindex="-1">16. 数据质量与对账 <a class="header-anchor" href="#_16-数据质量与对账" aria-label="Permalink to &quot;16. 数据质量与对账&quot;">​</a></h2><ol><li>为每张事实表声明 grain 和组成唯一键；任何重复键都阻断发布，而不是用 <code>DISTINCT</code> 隐藏。</li><li>按财务事件类型分别对账销售、退款、税费和净额，避免正负抵消掩盖漏数。</li><li>可加指标在事实粒度上检查单位和范围；汇率版本、币种与原币金额缺一不可。</li><li>每个事实 surrogate key 必须命中一个维度行；缺失业务键进入 unknown 行并单独统计，不能 inner join 丢事实。</li><li>SCD2 对每个 business ID 检查有效区间不重叠、边界规则一致且只有一个 current。</li><li>事实发生时刻必须落入所连接维度版本的 <code>[valid_from, valid_to)</code>，迟到事实也使用 event time。</li><li>维度晚到率和 unknown 回填量分别监控；补齐维度后重映射需保持事实金额与行数不变。</li><li>日期维度覆盖事实最小到最大日期，财务周、节假日等业务属性由受控版本维护。</li><li>snapshot fact 检查每主体每快照日最多一行，并区分存量余额与期间流量，禁止跨日直接求和半可加指标。</li><li>用小型 golden dataset 验证多商品订单、部分退款、客户迁移和边界时刻的预期聚合。</li></ol><h2 id="_17-调试与观测" tabindex="-1">17. 调试与观测 <a class="header-anchor" href="#_17-调试与观测" aria-label="Permalink to &quot;17. 调试与观测&quot;">​</a></h2><ol><li><code>fact_row_count</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>grain_duplicates</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>unknown_dimension_rate</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>scd_overlap</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>scd_gap</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>ledger_reconciliation</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>late_fact_rate</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>dimension_change</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>query_scan</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>semantic_test_fail</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li></ol><p>聚合异常先写出事实 grain，选一个订单项或客户，检查事实唯一键、金额符号、event time、surrogate key 和 SCD2 有效区间，再观察 SQL join 后行数是否膨胀。收入翻倍通常用 join 前后计数和键基数定位；历史地区变化则比较事实保存的维度 key，而不是只看 current 维度。</p><h2 id="_18-安全、成本与运维边界" tabindex="-1">18. 安全、成本与运维边界 <a class="header-anchor" href="#_18-安全、成本与运维边界" aria-label="Permalink to &quot;18. 安全、成本与运维边界&quot;">​</a></h2><ol><li>源凭据最小权限；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>PII分层访问和脱敏；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>原始层不可被普通BI任意下载；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>重跑/回填有资源配额；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>流批共享sink有容量仲裁；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>删除请求传播到派生层；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>schema发布兼容门禁；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>checkpoint/manifest备份；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>灾备恢复演练；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>成本按pipeline/dataset/tenant归集；事实表、维度表与星型模型 的实现要提供owner、runbook、停止阈值和审计记录。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“订单收入星型模型”，再以“客户地区SCD2”验证另一类时效/治理约束。提交数据样例、模型、质量测试、故障注入、lineage和成本面板。</p><ul><li>[ ] Grain 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Fact 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Dimension 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Star schema 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Surrogate key 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] SCD Type 1 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] SCD Type 2 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Date dimension 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] 两个案例包含输入、步骤、输出、验证、失败与重跑。</li><li>[ ] 源与目标按业务分片完成count/sum/version/hash对账。</li><li>[ ] 历史发布版本可回退，回填不压垮在线事实系统。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.kimballgroup.com/data-warehouse-business-intelligence-resources/kimball-techniques/" target="_blank" rel="noreferrer">Kimball Group dimensional modeling techniques</a>（访问日期：2026-07-17）</li><li><a href="https://docs.getdbt.com/blog/kimball-dimensional-model" target="_blank" rel="noreferrer">dbt dimensional modeling guide</a>（访问日期：2026-07-17）</li><li><a href="https://clickhouse.com/docs/guides/joining-tables" target="_blank" rel="noreferrer">ClickHouse JOIN guide</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/ddl-constraints.html" target="_blank" rel="noreferrer">PostgreSQL 18 constraints</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
